mapper.delete:
DELETE FROM blocks
WHERE block_code = #{blockCode}
  AND user_code  = #{userCode}

mapper.update:
UPDATE blocks
SET position = #{position}
WHERE block_code = #{blockCode}
  AND user_code  = #{userCode}

mapper.select:
SELECT l.log_code AS logCode, l.project_code AS projectCode, p.project_name AS projectName,
l.action_type AS actionType, l.target_type AS targetType, l.target_code AS targetCode,
CASE WHEN l.target_type = 'ISSUE' THEN i.title WHEN l.target_type = 'NOTICE' THEN n.title WHEN l.target_type = 'DOC' THEN da.original_name ELSE NULL END AS targetTitle,
l.created_at AS createdAt, l.meta AS meta FROM logs l JOIN projects p ON p.project_code = l.project_code LEFT JOIN issues i ON l.target_type = 'ISSUE' AND i.issue_code = l.target_code LEFT JOIN notices n ON l.target_type = 'NOTICE' AND n.notice_code = l.target_code LEFT JOIN documents_attachments da ON l.target_type = 'DOC' AND da.file_code = l.target_code WHERE l.user_code = #{userCode} AND l.created_at >= #{from} AND l.created_at <= #{to}
AND l.project_code = #{fixedProjectCode}
AND l.project_code IN
#{pc}
AND 1=0
AND ( (l.target_type = 'ISSUE' AND i.issue_code IS NOT NULL) OR (l.target_type = 'NOTICE' AND n.notice_code IS NOT NULL) OR (l.target_type = 'DOC' AND da.file_code IS NOT NULL) OR (l.target_type NOT IN ('ISSUE','NOTICE','DOC')) ) ORDER BY l.created_at DESC

SELECT project_name
FROM projects
WHERE project_code = #{projectCode}

choose.when:
CASE WHEN i.project_code IN
#{pc}
THEN 'Y' ELSE 'N' END
